/* 抽象分层接口（伪代码）*/

/* 第1层：DMA硬件抽象 */
typedef struct {
    DMA_Channel_TypeDef *channel;
    volatile uint32_t *CNDTR;
    volatile uint32_t *MAR;
    volatile uint32_t *PAR;
    volatile uint32_t *CCR;
} DMA_HW_Handle_t;

void DMA_HW_Config(DMA_HW_Handle_t *hw, uint32_t src, uint32_t dst, uint16_t len);
void DMA_HW_Start(DMA_HW_Handle_t *hw);
void DMA_HW_Stop(DMA_HW_Handle_t *hw);

/* 第2层：环形缓冲区（信息隐藏）*/
typedef struct {
    uint8_t *buffer;
    size_t size;
    volatile size_t head;  /* 生产者写，DMA ISR更新 */
    volatile size_t tail;  /* 消费者读，应用线程读取 */
} RingBuffer_t;

int RingBuffer_Push(RingBuffer_t *rb, uint8_t data);  /* 返回-1表示满 */
int RingBuffer_Pop(RingBuffer_t *rb, uint8_t *out);   /* 返回-1表示空 */

/* 第3层：应用层 - 只调用接口，不直接访问硬件 */
void App_ReadSensorData(uint8_t *buf, size_t len) {
    for (size_t i = 0; i < len; i++) {
        if (RingBuffer_Pop(&adc_ring, &buf[i]) != 0) break;
    }
}

/* STM32 HAL DMA 循环模式配置 - 完整示例 */
/* 适用于 STM32F4xx, ADC1 + DMA1_Channel1 */

/* 外部变量：ADC原始数据存放位置 */
extern ADC_HandleTypeDef hadc1;
extern DMA_HandleTypeDef hdma_adc1;

/* DMA 配置函数 - 在 SystemClock_Config() 后调用 */
void MX_DMA_Init(void) {
    /* 第1步：禁用DMA通道（配置前必须关闭）*/
    __HAL_DMA_DISABLE(&hdma_adc1);

    /* 第2步：等待DMA通道禁用生效 */
    while(hdma_adc1.Instance->CCR & DMA_CCR_EN);

    /* 第3步：配置DMA为循环模式 - 关键！*/
    hdma_adc1.Init.Mode      = DMA_CIRCULAR;     /* 循环模式，自动重载 */
    hdma_adc1.Init.Direction = DMA_PERIPH_TO_MEMORY;
    hdma_adc1.Init.PeriphInc = DMA_PINC_DISABLE;  /* 外设地址不递增 */
    hdma_adc1.Init.MemInc    = DMA_MINC_ENABLE;   /* 内存地址递增 */
    hdma_adc1.Init.PeriphDataAlignment = DMA_PDATAALIGN_HALFWORD; /* 16位 */
    hdma_adc1.Init.MemDataAlignment    = DMA_MDATAALIGN_HALFWORD;
    hdma_adc1.Init.Priority        = DMA_PRIORITY_MEDIUM;

    /* 第4步：重新初始化DMA（配置更改后必须调用）*/
    if (HAL_DMA_Init(&hdma_adc1) != HAL_OK) {
        Error_Handler();
    }

    /* 第5步：设置DMA通道与ADC的关联 */
    __HAL_LINKDMA(&hadc1, DMA_Handle, hdma_adc1);
}

/* 中断优先级配置 - 在 NVIC_Config() 中调用 */
void MX_DMA_NVIC_Config(void) {
    /* DMA中断优先级设置（数值越小优先级越高）*/
    /* 注意：ADC的DMA传输完成中断使用此通道 */
    HAL_NVIC_SetPriority(DMA1_Channel1_IRQn, 0, 0);  /* 最高优先级 */
    HAL_NVIC_EnableIRQ(DMA1_Channel1_IRQn);
}

/* DMA传输完成中断处理函数 - 放在 stm32f4xx_it.c */
void DMA1_Channel1_IRQHandler(void) {
    /* 方式1：使用HAL库统一入口（推荐）*/
    HAL_DMA_IRQHandler(&hdma_adc1);

    /* 方式2：手动清除标志（需要确保与HAL库不冲突）
    if (__HAL_DMA_GET_FLAG(&hdma_adc1, DMA_FLAG_TC1)) {
        __HAL_DMA_CLEAR_FLAG(&hdma_adc1, DMA_FLAG_TC1);
        // 更新缓冲区tail指针（用户代码）
    }
    if (__HAL_DMA_GET_FLAG(&hdma_adc1, DMA_FLAG_HT1)) {
        __HAL_DMA_CLEAR_FLAG(&hdma_adc1, DMA_FLAG_HT1);
        // 更新缓冲区tail到中间位置
    }
    */
}

/* 在ADC初始化后启动DMA（一次性配置，多次运行）*/
void Start_ADC_DMA(void) {
    /* 先停止（如果已经在运行）*/
    HAL_ADC_Stop_DMA(&hadc1);

    /* 配置内存地址和传输数量 */
    hdma_adc1.Instance->CMAR = (uint32_t)adc_raw_buffer;  /* 目标地址 */
    hdma_adc1.Instance->CNDTR = ADC_BUFFER_SIZE;           /* 传输数量 */

    /* 启动DMA */
    __HAL_DMA_ENABLE(&hdma_adc1);

    /* 启动ADC的DMA模式 */
    HAL_ADC_Start_DMA(&hadc1, (uint32_t*)adc_raw_buffer, ADC_BUFFER_SIZE);
}

