/* ringbuffer.c - 实现细节对调用者透明 */
#include "ringbuffer.h"
#include <stdlib.h>

/* 真正的结构体定义 - 隐藏实现细节 */
struct RingBufferImpl {
    uint8_t *buffer;
    size_t capacity;
    volatile size_t head;  /* 生产者（DMA ISR）写入 */
    volatile size_t tail;  /* 消费者（主循环）读取 */
};

/* 边界安全的写操作 - 模运算保证回绕 */
int RingBuffer_Push(RingBuffer_t *rb, uint8_t data) {
    size_t next_head = (rb->head + 1) % rb->capacity;
    if (next_head == rb->tail) {
        return -1;  /* 缓冲区满 */
    }
    rb->buffer[rb->head] = data;
    rb->head = next_head;
    return 0;
}

/* 边界安全的读操作 */
int RingBuffer_Pop(RingBuffer_t *rb, uint8_t *out) {
    if (rb->head == rb->tail) {
        return -1;  /* 缓冲区空 */
    }
    *out = rb->buffer[rb->tail];
    rb->tail = (rb->tail + 1) % rb->capacity;
    return 0;
}

